from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from datetime import datetime, timedelta

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///todos.db'
db = SQLAlchemy(app)

class TodoList(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(100), nullable=False)
    user_id = db.Column(db.Integer, nullable=False)
    todos = db.relationship('Todo', backref='todo_list', lazy='dynamic')

class Todo(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(100), nullable=False)
    description = db.Column(db.Text)
    due_date = db.Column(db.DateTime)
    completed = db.Column(db.Boolean, default=False)
    todo_list_id = db.Column(db.Integer, db.ForeignKey('todo_list.id'), nullable=False)

@app.route('/api/todo_lists', methods=['GET'])
def get_todo_lists():
    user_id = request.args.get('user_id')
    todo_lists = TodoList.query.filter_by(user_id=user_id).all()
    return jsonify([{'id': todo_list.id, 'name': todo_list.name} for todo_list in todo_lists])

@app.route('/api/todo_lists', methods=['POST'])
def create_todo_list():
    data = request.get_json()
    todo_list = TodoList(name=data['name'], user_id=data['user_id'])
    db.session.add(todo_list)
    db.session.commit()
    return jsonify({'id': todo_list.id, 'name': todo_list.name})

@app.route('/api/todo_lists/<int:list_id>', methods=['PUT'])
def update_todo_list(list_id):
    data = request.get_json()
    todo_list = TodoList.query.get(list_id)
    todo_list.name = data['name']
    db.session.commit()
    return jsonify({'id': todo_list.id, 'name': todo_list.name})

@app.route('/api/todo_lists/<int:list_id>', methods=['DELETE'])
def delete_todo_list(list_id):
    todo_list = TodoList.query.get(list_id)
    db.session.delete(todo_list)
    db.session.commit()
    return jsonify({'message': 'Todo list deleted'})

@app.route('/api/todos', methods=['GET'])
def get_todos():
    user_id = request.args.get('user_id')
    todo_lists = TodoList.query.filter_by(user_id=user_id).all()
    todos = [todo for todo_list in todo_lists for todo in todo_list.todos]
    return jsonify([{'id': todo.id, 'title': todo.title, 'description': todo.description, 'due_date': todo.due_date.isoformat(), 'completed': todo.completed, 'todo_list_id': todo.todo_list_id} for todo in todos])

@app.route('/api/todos', methods=['POST'])
def create_todo():
    data = request.get_json()
    todo = Todo(title=data['title'], description=data['description'], due_date=datetime.fromisoformat(data['due_date']), todo_list_id=data['todo_list_id'])
    db.session.add(todo)
    db.session.commit()
    return jsonify({'id': todo.id, 'title': todo.title, 'description': todo.description, 'due_date': todo.due_date.isoformat(), 'completed': todo.completed, 'todo_list_id': todo.todo_list_id})

@app.route('/api/todos/<int:todo_id>', methods=['PUT'])
def update_todo(todo_id):
    data = request.get_json()
    todo = Todo.query.get(todo_id)
    todo.title = data['title']
    todo.description = data['description']
    todo.due_date = datetime.fromisoformat(data['due_date'])
    todo.completed = data['completed']
    db.session.commit()
    return jsonify({'id': todo.id, 'title': todo.title, 'description': todo.description, 'due_date': todo.due_date.isoformat(), 'completed': todo.completed, 'todo_list_id': todo.todo_list_id})

@app.route('/api/todos/<int:todo_id>', methods=['DELETE'])
def delete_todo(todo_id):
    todo = Todo.query.get(todo_id)
    db.session.delete(todo)
    db.session.commit()
    return jsonify({'message': 'Todo deleted'})

@app.route('/api/progress', methods=['GET'])
def get_progress():
    user_id = request.args.get('user_id')
    todo_lists = TodoList.query.filter_by(user_id=user_id).all()
    total_tasks = 0
    completed_tasks = 0
    due_tasks = 0
    overdue_tasks = 0
    for todo_list in todo_lists:
        for todo in todo_list.todos:
            total_tasks += 1
            if todo.completed:
                completed_tasks += 1
            elif todo.due_date >= datetime.now():
                due_tasks += 1
            else:
                overdue_tasks += 1
    return jsonify({'total_tasks': total_tasks, 'completed_tasks': completed_tasks, 'due_tasks': due_tasks, 'overdue_tasks': overdue_tasks})

@app.route('/api/reminders', methods=['GET'])
def get_reminders():
    user_id = request.args.get('user_id')
    todo_lists = TodoList.query.filter_by(user_id=user_id).all()
    reminders = []
    for todo_list in todo_lists:
        for todo in todo_list.todos:
            if todo.due_date < datetime.now() + timedelta(days=7) and not todo.completed:
                reminders.append({'id': todo.id, 'title': todo.title, 'due_date': todo.due_date.isoformat(), 'todo_list_id': todo.todo_list_id})
    return jsonify(reminders)

if __name__ == '__main__':
    app.run(debug=True)

