import flask
from flask import Flask, request, jsonify
from datetime import datetime, timedelta
from typing import Dict, List

app = Flask(__name__)

# Database layer (assumed to be implemented separately)
class ToDoItem:
    def __init__(self, id: int, title: str, description: str, due_date: datetime, completed: bool):
        self.id = id
        self.title = title
        self.description = description
        self.due_date = due_date
        self.completed = completed

class ToDoList:
    def __init__(self, id: int, name: str, items: List[ToDoItem]):
        self.id = id
        self.name = name
        self.items = items

class DatabaseManager:
    def __init__(self):
        self.todo_lists = []
        self.todo_items = []

    def create_todo_list(self, name: str) -> ToDoList:
        new_list = ToDoList(len(self.todo_lists) + 1, name, [])
        self.todo_lists.append(new_list)
        return new_list

    def update_todo_list(self, list_id: int, name: str) -> ToDoList:
        for todo_list in self.todo_lists:
            if todo_list.id == list_id:
                todo_list.name = name
                return todo_list
        raise ValueError(f"ToDoList with id {list_id} not found.")

    def delete_todo_list(self, list_id: int):
        for i, todo_list in enumerate(self.todo_lists):
            if todo_list.id == list_id:
                del self.todo_lists[i]
                return
        raise ValueError(f"ToDoList with id {list_id} not found.")

    def create_todo_item(self, list_id: int, title: str, description: str, due_date: datetime) -> ToDoItem:
        new_item = ToDoItem(len(self.todo_items) + 1, title, description, due_date, False)
        for todo_list in self.todo_lists:
            if todo_list.id == list_id:
                todo_list.items.append(new_item)
                self.todo_items.append(new_item)
                return new_item
        raise ValueError(f"ToDoList with id {list_id} not found.")

    def update_todo_item(self, item_id: int, title: str, description: str, due_date: datetime, completed: bool) -> ToDoItem:
        for todo_item in self.todo_items:
            if todo_item.id == item_id:
                todo_item.title = title
                todo_item.description = description
                todo_item.due_date = due_date
                todo_item.completed = completed
                return todo_item
        raise ValueError(f"ToDoItem with id {item_id} not found.")

    def delete_todo_item(self, item_id: int):
        for i, todo_item in enumerate(self.todo_items):
            if todo_item.id == item_id:
                del self.todo_items[i]
                for todo_list in self.todo_lists:
                    todo_list.items = [item for item in todo_list.items if item.id != item_id]
                return
        raise ValueError(f"ToDoItem with id {item_id} not found.")

    def get_overdue_items(self) -> List[ToDoItem]:
        return [item for item in self.todo_items if not item.completed and item.due_date < datetime.now()]

    def get_due_soon_items(self, days: int) -> List[ToDoItem]:
        due_soon = []
        for item in self.todo_items:
            if not item.completed and item.due_date < datetime.now() + timedelta(days=days):
                due_soon.append(item)
        return due_soon

