db = SQLAlchemy(app)

class TodoList(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(100), nullable=False)
    items = db.relationship('TodoItem', backref='todolist', lazy='dynamic')

class TodoItem(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(100), nullable=False)
    due_date = db.Column(db.Date, nullable=False)
    is_complete = db.Column(db.Boolean, default=False)
    todolist_id = db.Column(db.Integer, db.ForeignKey('todolist.id'), nullable=False)

@app.route('/todolists', methods=['GET', 'POST'])
def handle_todolists():
    if request.method == 'GET':
        todolists = TodoList.query.all()
        return jsonify([todolist.name for todolist in todolists])
    elif request.method == 'POST':
        name = request.json['name']
        new_todolist = TodoList(name=name)
        db.session.add(new_todolist)
        db.session.commit()
        return jsonify({'id': new_todolist.id, 'name': new_todolist.name})

