def handle_todolist(todolist_id):
    todolist = TodoList.query.get(todolist_id)
    if not todolist:
        return jsonify({'error': 'TodoList not found'}), 404

    if request.method == 'GET':
        items = [{'id': item.id, 'name': item.name, 'due_date': item.due_date.strftime('%Y-%m-%d'), 'is_complete': item.is_complete} for item in todolist.items]
        return jsonify({'name': todolist.name, 'items': items})
