        new_name = request.json['name']
        todolist.name = new_name
        db.session.commit()
        return jsonify({'id': todolist.id, 'name': todolist.name})
    elif request.method == 'DELETE':
        db.session.delete(todolist)
        db.session.commit()
        return jsonify({'message': 'TodoList deleted'})

